CREATE EXTENSION IF NOT EXISTS plv8;
CREATE EXTENSION IF NOT EXISTS postgis;

CREATE EXTENSION IF NOT EXISTS ltree
WITH
  SCHEMA public;

DO $do$
BEGIN
   IF EXISTS (
      SELECT FROM pg_catalog.pg_roles
      WHERE  rolname = 'identity-manager') THEN

      RAISE NOTICE 'Role "identity-manager" already exists. Skipping.';
   ELSE
      CREATE ROLE "identity-manager";
   END IF;
END
$do$;

