CREATE OR REPLACE FUNCTION json_patch (input_json jsonb, patch_json json) RETURNS json LANGUAGE plv8 IMMUTABLE STRICT AS $_$
const module = { exports: {} };

{{{jsonpatch.js}}}

  /* If patch test fails, return the original to ensure upsert functionality can work  */
  const original = JSON.stringify(input_json || {});
  try {
    return module.exports.jsonpatch.apply(input_json || {}, patch_json);
  } catch (error) {
    if (error instanceof module.exports.PatchTestFailed) {
      return JSON.parse(original);
    }
    throw error;
  }
$_$;

CREATE OR REPLACE FUNCTION public.update_individual_profile (
  _individual_uuid uuid,
  _schema_name text,
  _instance_name text,
  _version integer,
  _patch_json json
) RETURNS jsonb LANGUAGE plpgsql AS $function$
DECLARE
  _individual_id bigint;
  _profile_schema_id int;
  _final_profile json;
  _enc boolean;
BEGIN
  SELECT individual_id INTO _individual_id FROM individuals WHERE individual_uuid = _individual_uuid;

  IF _individual_id IS NULL THEN
    RAISE EXCEPTION '[APP:NOTFOUND] No match individual found' USING ERRCODE = '22000';
  END IF;

  SELECT profile_schema_id, is_encrypted INTO _profile_schema_id, _enc FROM profile_schemas WHERE name = _schema_name;

  IF _profile_schema_id IS NULL THEN
    RAISE EXCEPTION '[IDENTITY:CONFIG] No profile schema found named %', _schema_name USING ERRCODE = '22000';
  END IF;
  IF _enc THEN
    RAISE EXCEPTION '[IDENTITY:CONFIG] Profile schema % is encrypted', _schema_name USING ERRCODE = '22000';
  END IF;

  IF _instance_name IS NOT NULL THEN
    INSERT INTO
  	individual_profiles as existing_profile
  	(individual_id, profile_schema_id, instance_name, version, profile)
    VALUES
  	(_individual_id, _profile_schema_id, _instance_name, _version, json_patch('{}', _patch_json))
    ON CONFLICT (individual_id, profile_schema_id, instance_name) WHERE instance_name IS NOT NULL AND deleted_at IS NULL
    DO UPDATE SET
  	profile = (json_patch(existing_profile.profile, _patch_json)),
    version = _version,
    updated_at = NOW()
    WHERE
  	existing_profile.individual_id = _individual_id
    AND existing_profile.instance_name = _instance_name
    AND existing_profile.profile_schema_id = _profile_schema_id
    RETURNING profile INTO _final_profile;
  ELSE
    INSERT INTO
  	individual_profiles as existing_profile
  	(individual_id, profile_schema_id, version, profile)
    VALUES
  	(_individual_id, _profile_schema_id, _version, json_patch('{}', _patch_json))
    ON CONFLICT (individual_id, profile_schema_id) WHERE instance_name IS NULL AND deleted_at IS NULL
    DO UPDATE SET
  	profile = (json_patch(existing_profile.profile, _patch_json)),
    version = _version,
    updated_at = NOW()
    WHERE
  	existing_profile.individual_id = _individual_id
    AND existing_profile.instance_name IS NULL
    AND existing_profile.profile_schema_id = _profile_schema_id
    RETURNING profile INTO _final_profile;
  END IF;

  RETURN _final_profile;
END
$function$;

CREATE OR REPLACE FUNCTION public.update_individual_encrypted_profile (
  _individual_uuid uuid,
  _schema_name text,
  _instance_name text,
  _version integer,
  key_id text,
  hex_key text,
  _patch_json json
) RETURNS text LANGUAGE plpgsql AS $function$
DECLARE
  _individual_id bigint;
  _profile_schema_id int;
  _final_profile bytea;
  _key bytea;
  _iv bytea;
  _enc boolean;
BEGIN
  SELECT individual_id INTO _individual_id FROM individuals WHERE individual_uuid = _individual_uuid;
  _key := decode(hex_key, 'hex');
  _iv := gen_random_bytes(16);

  IF _individual_id IS NULL THEN
    RAISE EXCEPTION '[APP:NOTFOUND] No match individual found' USING ERRCODE = '22000';
  END IF;

  SELECT profile_schema_id, is_encrypted INTO _profile_schema_id, _enc FROM profile_schemas WHERE name = _schema_name;

  IF _profile_schema_id IS NULL THEN
    RAISE EXCEPTION '[APP:CONFIG] No profile schema found named %', _schema_name USING ERRCODE = '22000';
  END IF;
  IF _enc = false THEN
    RAISE EXCEPTION '[APP:CONFIG] Profile schema % is not encrypted', _schema_name USING ERRCODE = '22000';
  END IF;

  IF _instance_name IS NOT NULL THEN
    INSERT INTO
    	individual_profiles as existing_profile
    	(individual_id, profile_schema_id, instance_name, version, profile, encrypted_profile)
    VALUES
  	  (_individual_id, _profile_schema_id, _instance_name, _version,
        to_jsonb(key_id),
        encrypt_json(json_patch('{}', _patch_json), _key, _iv)
      )
    ON CONFLICT (individual_id, profile_schema_id, instance_name) WHERE instance_name IS NOT NULL AND deleted_at IS NULL
    DO UPDATE SET
  	encrypted_profile = (
      encrypt_json(
        json_patch(
          decrypt_json(existing_profile.encrypted_profile, _key),
          _patch_json
        ),
        _key,
        _iv
      )
    ),
    version = _version,
    updated_at = NOW()
    WHERE
  	existing_profile.individual_id = _individual_id
    AND existing_profile.instance_name = _instance_name
    AND existing_profile.profile_schema_id = _profile_schema_id
    RETURNING encrypted_profile INTO _final_profile;
  ELSE
    INSERT INTO
    	individual_profiles as existing_profile
    	(individual_id, profile_schema_id, version, profile, encrypted_profile)
    VALUES
  	  (_individual_id, _profile_schema_id, _version,
        to_jsonb(key_id),
        encrypt_json(json_patch('{}', _patch_json), _key, _iv)
      )
    ON CONFLICT (individual_id, profile_schema_id) WHERE instance_name IS NULL AND deleted_at IS NULL
    DO UPDATE SET
  	encrypted_profile = (
      encrypt_json(
        json_patch(
          decrypt_json(existing_profile.encrypted_profile, _key),
          _patch_json
        ),
        _key,
        _iv
      )
    ),
    version = _version,
    updated_at = NOW()
    WHERE
  	existing_profile.individual_id = _individual_id
    AND existing_profile.instance_name IS NULL
    AND existing_profile.profile_schema_id = _profile_schema_id
    RETURNING encrypted_profile INTO _final_profile;
  END IF;

  RETURN encode(_final_profile, 'hex');
END
$function$;

CREATE TYPE upserted_individual AS (
  inserted BOOLEAN,
  individual_id INTEGER,
  individual_uuid UUID,
  error text,
  created_at TIMESTAMP
);

CREATE OR REPLACE FUNCTION public.upsert_identifier (
  _namespace_name text,
  _identifier text,
  _display_identifier text,
  _is_unique boolean,
  _released_at timestamp without time zone DEFAULT NULL::timestamp without time zone
) RETURNS upserted_individual LANGUAGE plpgsql AS $function$

DECLARE
  _namespace_id int;
  _indvidual_id int;
  _inserted boolean;
  _individual upserted_individual;

BEGIN
  SELECT
    identifier_namespace_id, type
  INTO
    _namespace_id
  FROM
    identifier_namespaces
  WHERE
    name = _namespace_name;

  IF _namespace_id IS NULL THEN
    RAISE EXCEPTION '[APP:CONFIG] No namespace found matching %', _namespace_name USING ERRCODE = '22000';
  END IF;

  SELECT
    individual_id, false
  INTO
    _indvidual_id, _inserted
  FROM
    individual_identifiers
  WHERE
    identifier_namespace_id = _namespace_id
    AND _is_unique = true
    AND identifier = _identifier
    AND released_at IS NULL;

  IF _indvidual_id IS NULL THEN
    _inserted := true;
    INSERT INTO individuals DEFAULT VALUES RETURNING individual_id INTO _indvidual_id;
    INSERT INTO individual_identifiers
      (individual_id, is_unique, identifier, display_identifier, identifier_namespace_id, released_at)
    VALUES
      (_indvidual_id, _is_unique, _identifier, _display_identifier, _namespace_id, _released_at);
  END IF;

  SELECT
    individual_id, individual_uuid, created_at, _inserted, _identifier
  INTO
    _individual.individual_id, _individual.individual_uuid,
    _individual.created_at, _individual.inserted, _individual.identifier
  FROM
    individuals
  WHERE
    individual_id = _indvidual_id;

  RETURN _individual;
END
$function$;

CREATE TYPE identifier_detail AS (
  identifier_namespace_id INTEGER,
  identifier text,
  display_identifier text,
  is_unique boolean
);

CREATE OR REPLACE FUNCTION public.upsert_identifiers (_individual_uuid uuid, _jsonidentifiers json) RETURNS upserted_individual LANGUAGE plpgsql AS $function$
DECLARE
	_individual_id int;
  _min_id int;
  _max_id int;
  _inserted boolean;
	_individual upserted_individual;
  _identifiers identifier_detail[];
BEGIN
  WITH cte AS (
    SELECT x
    FROM json_populate_recordset(NULL::identifier_detail, _jsonIdentifiers) AS x
  )
  SELECT array_agg(x) INTO _identifiers FROM cte;

  IF _individual_uuid IS NOT NULL THEN
    SELECT
      individual_id
    INTO
      _individual_id
    FROM
      individuals
    WHERE
      individual_uuid = _individual_uuid;
  END IF;

  WITH passed AS (
    SELECT identifier_namespace_id, identifier
    FROM unnest(_identifiers) p
    WHERE p.is_unique = true
  )
  SELECT
    MIN(individual_id),
    MAX(individual_id)
  INTO
    _min_id, _max_id
  FROM
    individual_identifiers a
    INNER JOIN passed p ON
      a.identifier = p.identifier
      AND a.identifier_namespace_id = p.identifier_namespace_id
      AND a.released_at IS NULL
      AND a.is_unique IS TRUE;

  IF (_min_id IS NOT NULL AND _min_id <> _max_id)
    OR (_individual_uuid IS NOT NULL AND _min_id IS NOT NULL AND (_individual_id IS NULL OR _individual_id <> _min_id)) THEN
    SELECT individual_id, individual_uuid, 'CONFLICT'
    INTO _individual.individual_id, _individual.individual_uuid, _individual.error
    FROM individuals
    WHERE individual_id = _min_id;
    RETURN _individual;
  END IF;

  IF _min_id IS NOT NULL THEN
    _individual_id := _min_id;
  END IF;

  IF _individual_id IS NULL THEN
    _inserted := true;
    IF _individual_uuid IS NOT NULL THEN
      INSERT INTO individuals (individual_uuid) VALUES (_individual_uuid) RETURNING individual_id INTO _individual_id;
    ELSE
      INSERT INTO individuals DEFAULT VALUES RETURNING individual_id INTO _individual_id;
    END IF;
	END IF;

  WITH passed AS (
    SELECT p.identifier, p.display_identifier, p.is_unique, p.identifier_namespace_id
    FROM unnest(_identifiers) p
  )
  INSERT INTO
    individual_identifiers (individual_id, is_unique, identifier, display_identifier, identifier_namespace_id)
  SELECT
    _individual_id,
    is_unique,
    identifier,
    display_identifier,
    identifier_namespace_id
  FROM passed p
  -- TODO insert where not exists is not atomic I don't think, so this could use a fixup
  WHERE NOT EXISTS
    (SELECT 1 FROM individual_identifiers i2 WHERE
      p.identifier_namespace_id = i2.identifier_namespace_id AND
      i2.identifier = p.identifier AND i2.released_at IS NULL AND
      i2.individual_id = _individual_id);

  SELECT
		individual_id, individual_uuid, created_at, _inserted
	INTO
		_individual.individual_id, _individual.individual_uuid, _individual.created_at, _individual.inserted
	FROM
		individuals
	WHERE
		individual_id = _individual_id;

	RETURN _individual;
END
$function$;

